        #return QtCore.QVariant(self.model.data(index))
            return QtCore.QVariant(self.model.data(index))

    def headerData(self, col, orientation, role):
        if orientation == QtCore.Qt.Horizontal and role == QtCore.Qt.DisplayRole:
            return QtCore.QVariant()
